solution_code:
#include <iostream>

int main() {
    int n{}, d{};
    std::cin >> n >> d;

    int sum{0};
    for (int i{1}; i <= n; ++i) {
        if (i % d == 0) {
            sum += i;
        }
    }

    std::cout << "Sum: " << sum << "\n";
    return 0;
}

