solution_code:
#include <iostream>

int countEvens(int low, int high) {
    int count{0};
    for (int i{low}; i <= high; ++i) {
        if (i % 2 == 0) {
            ++count;
        }
    }
    return count;
}

int main() {
    int low{}, high{};
    std::cin >> low >> high;
    std::cout << "Count: " << countEvens(low, high) << "\n";
    return 0;
}
